//! Database seeder binary for module: billing
//!
//! Generated by backbone-schema. Do not edit manually.
//!
//! Run with: cargo run --bin billing-seeder
//! Or via CLI: backbone seed run --module billing
//!
//! This binary runs all registered seeders in order.

use anyhow::Result;
use sqlx::postgres::PgPoolOptions;
use std::env;

// Import seeders
use backbone_billing::seeders::SeedAgentEarningSeeder;
use backbone_billing::seeders::SeedFinancialPeriodSeeder;
use backbone_billing::seeders::SeedPaymentSeeder;
use backbone_billing::seeders::SeedPaymentGatewayDetailSeeder;
use backbone_billing::seeders::SeedPaymentFeeSeeder;
use backbone_billing::seeders::SeedInvoiceSeeder;
use backbone_billing::seeders::SeedInvoicePartySeeder;
use backbone_billing::seeders::SeedInvoiceLineItemSeeder;
use backbone_billing::seeders::SeedProviderBankAccountSeeder;
use backbone_billing::seeders::SeedRefundRequestSeeder;
use backbone_billing::seeders::SeedSettlementSeeder;
use backbone_billing::seeders::Seeder;

#[tokio::main]
async fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    let force = args.iter().any(|a| a == "--force");
    let filter: Option<&str> = args.iter()
        .skip(1)
        .find(|a| !a.starts_with("-"))
        .map(|s| s.as_str());

    let database_url = env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set");

    println!("Connecting to database...");

    let pool = PgPoolOptions::new()
        .max_connections(5)
        .connect(&database_url)
        .await?;

    println!("Connected to database");
    println!();
    println!("Running seeders for module: billing");
    println!();

    // Register seeders in order
    let mut seeders: Vec<Box<dyn Seeder + Send + Sync>> = Vec::new();
    seeders.push(Box::new(SeedAgentEarningSeeder::new()));
    seeders.push(Box::new(SeedFinancialPeriodSeeder::new()));
    seeders.push(Box::new(SeedPaymentSeeder::new()));
    seeders.push(Box::new(SeedPaymentGatewayDetailSeeder::new()));
    seeders.push(Box::new(SeedPaymentFeeSeeder::new()));
    seeders.push(Box::new(SeedInvoiceSeeder::new()));
    seeders.push(Box::new(SeedInvoicePartySeeder::new()));
    seeders.push(Box::new(SeedInvoiceLineItemSeeder::new()));
    seeders.push(Box::new(SeedProviderBankAccountSeeder::new()));
    seeders.push(Box::new(SeedRefundRequestSeeder::new()));
    seeders.push(Box::new(SeedSettlementSeeder::new()));

    // Sort by order
    seeders.sort_by_key(|s| s.order());

    // Run seeders
    for seeder in &seeders {
        let name = seeder.name();

        // Apply filter if specified
        if let Some(f) = filter {
            if !name.contains(f) {
                continue;
            }
        }

        if force {
            println!("   Running {}...", name);
            seeder.run(&pool).await?;
            println!("   {} completed", name);
        } else {
            println!("   Checking {}...", name);
            if seeder.should_run(&pool).await? {
                println!("   Running {}...", name);
                seeder.run(&pool).await?;
                println!("   {} completed", name);
            } else {
                println!("   {} already applied, skipping", name);
            }
        }
    }

    println!();
    println!("All seeders completed successfully!");

    Ok(())
}
